module traffic_light
(
    input rst_n,
    input clk,
    input pass_request,
    output [7:0] clock,
    output red
);
parameter idle = 2'b00;
parameter s1_red = 2'b01;
parameter s2_yellow = 2'b10;
parameter s3_green = 2'b11;
reg [1:0] state;
reg [1:0] next_state;
reg [7:0] cnt;
reg [7:0] next_cnt;
reg p_red, p_yellow, p_green;
reg next_red, next_yellow, next_green;
always @(posedge clk or negedge rst_n) begin
    if(!rst_n) begin
        state <= idle;
        cnt <= 8'd10;
        {p_red, p_yellow, p_green} <= 3'b0;
    end
    else begin
        state <= next_state;
        cnt <= next_cnt;
        {p_red, p_yellow, p_green} <= {next_red, next_yellow, next_green};
    end
end
always @(*) begin
    case(state)
        idle: begin
            next_state = s1_red;
            next_cnt = cnt;
            {next_red, next_yellow, next_green} = 3'b0;
        end
        s1_red: begin
            next_state = (cnt == 8'd3) ? s3_green : s1_red;
            next_cnt = (cnt == 8'd3) ? 8'd60 : cnt - 8'd1;
            {next_red, next_yellow, next_green} = (cnt == 8'd3) ? 3'b0 : {p_red, p_yellow, p_green};
        end
        s2_yellow: begin
            next_state = (cnt == 8'd3) ? s1_red : s2_yellow;
            next_cnt = (cnt == 8'd3) ? 8'd10 : cnt - 8'd1;
            {next_red, next_yellow, next_green} = (cnt == 8'd3) ? 3'b0 : {p_red, p_yellow, p_green};
        end
        s3_green: begin
            next_state = (cnt == 8'd3) ? s2_yellow : s3_green;
            next_cnt = (cnt == 8'd3) ? 8'd5 : cnt - 8'd1;
            {next_red, next_yellow, next_green} = (cnt == 8'd3) ? 3'b0 : {p_red, p_yellow, p_green};
        end
        default: begin
            next_state = idle;
            next_cnt = cnt;
            {next_red, next_yellow, next_green} = 3'b0;
        end
    endcase
end
always @(posedge clk or negedge rst_n) begin
    if(!rst_n) begin
        next_cnt = 8'd10;
    end
    else begin
        if(pass_request && s3_green) begin
            next_cnt = 8'd10;
        end
        else if(!s3_green && p_green) begin
            next_cnt = 8'd60;
        end
        else if(!s2_yellow && p_yellow) begin
            next_cnt = 8'd5;
        end
        else if(!s1_red && p_red) begin
            next_cnt = 8'd10;
        end
        else begin
            next_cnt = cnt - 8'd1;
        end
    end
end
assign clock = cnt;
always @(posedge clk or negedge rst_n) begin
    if(!rst_n) begin
        {red, yellow, green} <= 3'b0;
    end
    else begin
        {red, yellow, green} <= {p_red, p_yellow, p_green};
    end
end
endmodule
